217→fn host_terminal_apply_tmux_profile() {
218→    let commands: &[&[&str]] = &[
219→        &["set-option", "-g", "status", "off"],
220→        &["set-option", "-g", "mouse", "off"],
221→        &["set-window-option", "-g", "window-size", "latest"],
222→        &["set-option", "-g", "allow-rename", "off"],
