234→                let stderr = stderr.trim();
235→                if stderr.is_empty() {
236→                    debug!(
237→                        command = ?args,
238→                        status = %output.status,
239→                        "tmux profile command failed for host terminal"
240→                    );
241→                } else {
242→                    debug!(
243→                        command = ?args,
244→                        status = %output.status,
245→                        error = stderr,
246→                        "tmux profile command failed for host terminal"
247→                    );
248→                }
249→            },
250→            Err(err) => {
251→                debug!(
252→                    command = ?args,
253→                    error = %err,
254→                    "failed to execute tmux profile command for host terminal"
255→                );
256→            },
257→        }
258→    }
259→}
