272→fn host_terminal_normalize_window_target(target: &str) -> Option<String> {
273→    let trimmed = target.trim();
274→    if trimmed.is_empty() {
275→        return None;
276→    }
277→    if let Some(rest) = trimmed.strip_prefix('@') {
278→        if !rest.is_empty() && rest.chars().all(|c| c.is_ascii_digit()) {
279→            return Some(trimmed.to_string());
280→        }
281→        return None;
282→    }
283→    if trimmed.chars().all(|c| c.is_ascii_digit()) {
284→        return Some(trimmed.to_string());
285→    }
286→    None
287→}
