289→fn host_terminal_resolve_window_target(
290→    windows: &[HostTerminalWindowInfo],
291→    requested: &str,
292→) -> Option<String> {
293→    let normalized = host_terminal_normalize_window_target(requested)?;
294→    if normalized.starts_with('@') {
295→        return windows
296→            .iter()
297→            .find(|window| window.id == normalized)
298→            .map(|window| window.id.clone());
299→    }
300→    let requested_index = normalized.parse::<u32>().ok()?;
301→    windows
302→        .iter()
303→        .find(|window| window.index == requested_index)
304→        .map(|window| window.id.clone())
305→}
