315→fn host_terminal_ensure_tmux_session() -> TerminalResult<()> {
316→    let mut has_cmd = host_terminal_tmux_command();
317→    let has_output = has_cmd
318→        .args(["has-session", "-t", HOST_TERMINAL_SESSION_NAME])
319→        .output()
320→        .map_err(|err| format!("failed to check tmux session: {err}"))?;
321→    if has_output.status.success() {
322→        return Ok(());
323→    }
324→
325→    let mut create_cmd = host_terminal_tmux_command();
326→    create_cmd.args(["new-session", "-d", "-s", HOST_TERMINAL_SESSION_NAME]);
327→    if let Some(working_dir) = host_terminal_working_dir() {
328→        create_cmd.arg("-c").arg(working_dir);
329→    }
330→    let create_output = create_cmd
331→        .output()
332→        .map_err(|err| format!("failed to create tmux session: {err}"))?;
333→    if create_output.status.success() {
334→        return Ok(());
335→    }
336→
337→    let mut retry_has_cmd = host_terminal_tmux_command();
338→    let retry_has_output = retry_has_cmd
339→        .args(["has-session", "-t", HOST_TERMINAL_SESSION_NAME])
340→        .output()
341→        .map_err(|err| format!("failed to re-check tmux session: {err}"))?;
342→    if retry_has_output.status.success() {
343→        return Ok(());
344→    }
345→
346→    let stderr = String::from_utf8_lossy(&create_output.stderr);
347→    let stderr = stderr.trim();
348→    if stderr.is_empty() {
349→        Err(format!(
350→            "failed to create tmux session '{}' (exit {})",
351→            HOST_TERMINAL_SESSION_NAME, create_output.status
352→        )
353→        .into())
354→    } else {
355→        Err(format!(
356→            "failed to create tmux session '{}': {}",
357→            HOST_TERMINAL_SESSION_NAME, stderr
358→        )
359→        .into())
360→    }
361→}
