363→fn host_terminal_parse_tmux_window_line(line: &str) -> Option<HostTerminalWindowInfo> {
364→    let mut parts = line.splitn(4, '\t');
365→    let id = parts.next()?.trim();
366→    let index = parts.next()?.trim().parse::<u32>().ok()?;
367→    let name = parts.next()?.trim();
368→    let active_raw = parts.next()?.trim();
369→    let active = active_raw == "1";
370→    let id = host_terminal_normalize_window_target(id).filter(|value| value.starts_with('@'))?;
371→    Some(HostTerminalWindowInfo {
372→        id,
373→        index,
374→        name: name.to_string(),
375→        active,
376→    })
377→}
