389→        .output()
390→        .map_err(|err| format!("failed to list tmux windows: {err}"))?;
391→    if !output.status.success() {
392→        let stderr = String::from_utf8_lossy(&output.stderr);
393→        let stderr = stderr.trim();
394→        if stderr.is_empty() {
395→            return Err(format!("failed to list tmux windows (exit {})", output.status).into());
396→        }
397→        return Err(format!("failed to list tmux windows: {stderr}").into());
398→    }
399→    let stdout = String::from_utf8_lossy(&output.stdout);
400→    let mut windows: Vec<HostTerminalWindowInfo> = stdout
401→        .lines()
402→        .filter_map(host_terminal_parse_tmux_window_line)
403→        .collect();
404→    windows.sort_by_key(|window| window.index);
405→    Ok(windows)
406→}
