408→fn host_terminal_tmux_create_window(name: Option<&str>) -> TerminalResult<String> {
409→    let mut cmd = host_terminal_tmux_command();
410→    cmd.args([
411→        "new-window",
412→        "-d",
413→        "-t",
414→        HOST_TERMINAL_SESSION_NAME,
415→        "-P",
416→        "-F",
417→        "#{window_id}",
418→    ]);
419→    if let Some(name) = name {
420→        cmd.args(["-n", name]);
421→    }
422→    let output = cmd
423→        .output()
424→        .map_err(|err| format!("failed to create tmux window: {err}"))?;
425→    if !output.status.success() {
426→        let stderr = String::from_utf8_lossy(&output.stderr);
427→        let stderr = stderr.trim();
428→        if stderr.is_empty() {
429→            return Err(format!("failed to create tmux window (exit {})", output.status).into());
430→        }
431→        return Err(format!("failed to create tmux window: {stderr}").into());
432→    }
433→    let window_id_raw = String::from_utf8_lossy(&output.stdout).trim().to_string();
434→    let window_id = host_terminal_normalize_window_target(&window_id_raw)
435→        .filter(|value| value.starts_with('@'))
436→        .ok_or_else(|| "tmux did not return a valid window id".to_string())?;
437→    Ok(window_id)
438→}
