440→fn host_terminal_tmux_select_window(window_target: &str) -> TerminalResult<()> {
441→    let mut cmd = host_terminal_tmux_command();
442→    let output = cmd
443→        .args(["select-window", "-t", window_target])
444→        .output()
445→        .map_err(|err| format!("failed to select tmux window: {err}"))?;
446→    if output.status.success() {
447→        return Ok(());
448→    }
449→    let stderr = String::from_utf8_lossy(&output.stderr);
450→    let stderr = stderr.trim();
451→    if stderr.is_empty() {
452→        Err(format!(
453→            "failed to select tmux window '{}' (exit {})",
454→            window_target, output.status
455→        )
456→        .into())
457→    } else {
458→        Err(format!(
459→            "failed to select tmux window '{}': {}",
460→            window_target, stderr
461→        )
462→        .into())
463→    }
