466→fn host_terminal_tmux_reset_window_size(window_target: Option<&str>) {
467→    let target = window_target.unwrap_or(HOST_TERMINAL_SESSION_NAME);
468→    let mut cmd = host_terminal_tmux_command();
469→    let output = cmd.args(["resize-window", "-A", "-t", target]).output();
470→    match output {
471→        Ok(output) if output.status.success() => {},
472→        Ok(output) => {
473→            let stderr = String::from_utf8_lossy(&output.stderr);
474→            let stderr = stderr.trim();
475→            if stderr.is_empty() {
476→                debug!(
477→                    target,
478→                    status = %output.status,
479→                    "tmux resize-window -A failed while resetting host terminal window size"
480→                );
481→            } else {
482→                debug!(
483→                    target,
484→                    status = %output.status,
485→                    error = stderr,
486→                    "tmux resize-window -A failed while resetting host terminal window size"
487→                );
488→            }
489→        },
490→        Err(err) => {
491→            debug!(
492→                target,
493→                error = %err,
494→                "failed to invoke tmux resize-window -A for host terminal window size reset"
495→            );
496→        },
497→    }
498→}
