500→fn host_terminal_command_builder(use_tmux_persistence: bool) -> CommandBuilder {
501→    if use_tmux_persistence {
502→        let mut cmd = CommandBuilder::new("tmux");
503→        host_terminal_apply_tmux_common_args(&mut cmd);
504→        cmd.args(["new-session", "-A", "-s", HOST_TERMINAL_SESSION_NAME]);
505→        host_terminal_apply_env(&mut cmd);
506→        if let Some(working_dir) = host_terminal_working_dir() {
507→            cmd.cwd(working_dir);
508→        }
509→        return cmd;
510→    }
511→
512→    if cfg!(windows) {
513→        let comspec = std::env::var("COMSPEC")
514→            .ok()
515→            .filter(|value| !value.trim().is_empty())
516→            .unwrap_or_else(|| "cmd.exe".to_string());
517→        let mut cmd = CommandBuilder::new(comspec);
518→        host_terminal_apply_env(&mut cmd);
519→        if let Some(working_dir) = host_terminal_working_dir() {
520→            cmd.cwd(working_dir);
521→        }
522→        return cmd;
523→    }
524→
525→    let shell = std::env::var("SHELL")
526→        .ok()
527→        .filter(|value| !value.trim().is_empty())
528→        .unwrap_or_else(|| "/bin/sh".to_string());
529→    let mut cmd = CommandBuilder::new(shell);
530→    host_terminal_apply_env(&mut cmd);
531→    cmd.arg("-l");
532→    if let Some(working_dir) = host_terminal_working_dir() {
533→        cmd.cwd(working_dir);
534→    }
535→    cmd
536→}
