538→fn spawn_host_terminal_runtime(
539→    cols: u16,
540→    rows: u16,
541→    use_tmux_persistence: bool,
542→    tmux_window_target: Option<&str>,
543→) -> TerminalResult<HostTerminalPtyRuntime> {
544→    if use_tmux_persistence {
545→        host_terminal_ensure_tmux_session()?;
546→        if let Some(target) = tmux_window_target {
547→            host_terminal_tmux_select_window(target)?;
548→        }
549→        host_terminal_tmux_reset_window_size(tmux_window_target);
550→    }
551→    let pty_system = native_pty_system();
552→    let pair = pty_system
553→        .openpty(PtySize {
554→            rows: rows.max(1),
555→            cols: cols.max(2),
556→            pixel_width: 0,
557→            pixel_height: 0,
558→        })
559→        .map_err(|err| format!("failed to allocate host PTY: {err}"))?;
560→
561→    let portable_pty::PtyPair { master, slave } = pair;
562→    let cmd = host_terminal_command_builder(use_tmux_persistence);
563→    let child = slave
564→        .spawn_command(cmd)
565→        .map_err(|err| format!("failed to spawn host shell: {err}"))?;
566→    drop(slave);
567→
568→    if use_tmux_persistence {
569→        host_terminal_apply_tmux_profile();
570→    }
571→
572→    let writer = master
573→        .take_writer()
574→        .map_err(|err| format!("failed to open host terminal writer: {err}"))?;
575→    let reader = master
576→        .try_clone_reader()
577→        .map_err(|err| format!("failed to open host terminal reader: {err}"))?;
578→    let output_rx = spawn_host_terminal_reader(reader)?;
579→
580→    Ok(HostTerminalPtyRuntime {
581→        master,
582→        writer,
583→        child,
584→        output_rx,
585→    })
586→}
587→
588→fn spawn_host_terminal_reader(
589→    mut reader: Box<dyn Read + Send>,
590→) -> TerminalResult<tokio::sync::mpsc::UnboundedReceiver<HostTerminalOutputEvent>> {
591→    let (tx, rx) = tokio::sync::mpsc::unbounded_channel::<HostTerminalOutputEvent>();
592→    std::thread::Builder::new()
593→        .name("moltis-host-terminal-reader".to_string())
594→        .spawn(move || {
595→            let mut buf = vec![0_u8; 16 * 1024];
596→            loop {
597→                match reader.read(&mut buf) {
598→                    Ok(0) => {
599→                        let _ = tx.send(HostTerminalOutputEvent::Closed);
600→                        break;
601→                    },
602→                    Ok(n) => {
603→                        if tx
604→                            .send(HostTerminalOutputEvent::Output(buf[..n].to_vec()))
605→                            .is_err()
606→                        {
607→                            return;
608→                        }
609→                    },
610→                    Err(err) if err.kind() == std::io::ErrorKind::Interrupted => continue,
611→                    Err(err) => {
612→                        let _ = tx.send(HostTerminalOutputEvent::Error(format!(
613→                            "host terminal stream error: {err}"
614→                        )));
615→                        let _ = tx.send(HostTerminalOutputEvent::Closed);
616→                        break;
617→                    },
618→                }
619→            }
620→        })
621→        .map_err(|err| format!("failed to launch host terminal reader thread: {err}"))?;
622→    Ok(rx)
623→}
