625→fn host_terminal_write_input(
626→    runtime: &mut HostTerminalPtyRuntime,
627→    input: &str,
628→) -> TerminalResult<()> {
629→    runtime
630→        .writer
631→        .write_all(input.as_bytes())
632→        .map_err(|err| format!("failed to write to host terminal: {err}"))?;
633→    runtime
634→        .writer
635→        .flush()
636→        .map_err(|err| format!("failed to flush host terminal input: {err}"))?;
637→    Ok(())
638→}
