663→fn detect_host_root_user_for_terminal() -> Option<bool> {
664→    if cfg!(windows) {
665→        return None;
666→    }
667→
668→    if let Some(uid) = std::env::var("EUID")
669→        .ok()
670→        .or_else(|| std::env::var("UID").ok())
671→        .and_then(|value| value.trim().parse::<u32>().ok())
672→    {
673→        return Some(uid == 0);
674→    }
675→
676→    if let Some(user) = std::env::var("USER")
677→        .ok()
678→        .or_else(|| std::env::var("LOGNAME").ok())
679→    {
680→        let trimmed = user.trim();
681→        if !trimmed.is_empty() {
682→            return Some(trimmed == "root");
683→        }
684→    }
685→
686→    None
687→}
