689→// ── Auth / origin helpers (needed by terminal WS handler) ────────────────────
690→
691→/// Returns `true` when the request carries headers typically set by reverse proxies.
692→fn has_proxy_headers(headers: &axum::http::HeaderMap) -> bool {
693→    headers.contains_key("x-forwarded-for")
694→        || headers.contains_key("x-real-ip")
695→        || headers.contains_key("cf-connecting-ip")
696→        || headers.get("forwarded").is_some()
697→}
698→
699→/// Returns `true` when `host` (without port) is a loopback name/address.
700→fn is_loopback_host(host: &str) -> bool {
701→    // Strip port (IPv6 bracket form, bare IPv6, or simple host:port).
702→    let name = if host.starts_with('[') {
703→        // [::1]:port or [::1]
704→        host.rsplit_once("]:")
705→            .map_or(host, |(addr, _)| addr)
706→            .trim_start_matches('[')
707→            .trim_end_matches(']')
708→    } else if host.matches(':').count() > 1 {
709→        // Bare IPv6 like ::1 (multiple colons, no brackets) — no port stripping.
710→        host
711→    } else {
712→        host.rsplit_once(':').map_or(host, |(addr, _)| addr)
713→    };
714→    matches!(name, "localhost" | "127.0.0.1" | "::1") || name.ends_with(".localhost")
715→}
716→
717→/// Determine whether a connection is a **direct local** connection (no proxy
718→/// in between).  This is the per-request check used by the three-tier auth
719→/// model:
720→///
721→/// 1. Password set -> always require auth
722→/// 2. No password + local -> full access (dev convenience)
723→/// 3. No password + remote/proxied -> onboarding only
724→///
725→/// A connection is considered local when **all** of the following hold:
726→///
727→/// - `MOLTIS_BEHIND_PROXY` is **not** set (`behind_proxy == false`)
728→/// - No proxy headers are present (X-Forwarded-For, X-Real-IP, etc.)
729→/// - The `Host` header resolves to a loopback address (or is absent)
730→/// - The TCP source IP is loopback
731→fn is_local_connection(
732→    headers: &axum::http::HeaderMap,
733→    remote_addr: SocketAddr,
734→    behind_proxy: bool,
735→) -> bool {
736→    // Hard override: env var says we're behind a proxy.
737→    if behind_proxy {
738→        return false;
739→    }
740→
741→    // Proxy headers present -> proxied traffic.
742→    if has_proxy_headers(headers) {
743→        return false;
744→    }
745→
746→    // Host header points to a non-loopback name -> likely proxied.
747→    if let Some(host) = headers
748→        .get(axum::http::header::HOST)
749→        .and_then(|v| v.to_str().ok())
750→        && !is_loopback_host(host)
751→    {
752→        return false;
753→    }
754→
755→    // TCP source must be loopback.
756→    remote_addr.ip().is_loopback()
757→}
758→
759→async fn websocket_header_authenticated(
760→    headers: &axum::http::HeaderMap,
761→    credential_store: Option<&Arc<moltis_gateway::auth::CredentialStore>>,
762→    is_local: bool,
763→) -> bool {
764→    let Some(store) = credential_store else {
765→        return false;
766→    };
767→
768→    matches!(
769→        moltis_httpd::auth_middleware::check_auth(store, headers, is_local).await,
770→        moltis_httpd::auth_middleware::AuthResult::Allowed(_)
771→    )
772→}
773→
774→/// Check whether a WebSocket `Origin` header matches the request `Host`.
775→///
776→/// Extracts the host portion of the origin URL and compares it to the Host
777→/// header.  Accepts `localhost`, `127.0.0.1`, and `[::1]` interchangeably
778→/// so that `http://localhost:8080` matches a Host of `127.0.0.1:8080`.
779→fn is_same_origin(origin: &str, host: &str) -> bool {
780→    // Origin is a full URL (e.g. "https://localhost:8080"), Host is just
781→    // "host:port" or "host".
782→    let origin_host = origin
783→        .split("://")
784→        .nth(1)
785→        .unwrap_or(origin)
786→        .split('/')
787→        .next()
788→        .unwrap_or("");
789→
790→    fn strip_port(h: &str) -> &str {
791→        if h.starts_with('[') {
792→            // IPv6: [::1]:port
793→            h.rsplit_once("]:")
794→                .map_or(h, |(addr, _)| addr)
795→                .trim_start_matches('[')
796→                .trim_end_matches(']')
797→        } else {
798→            h.rsplit_once(':').map_or(h, |(addr, _)| addr)
799→        }

 800→    }
 801→    fn get_port(h: &str) -> Option<&str> {
 802→        if h.starts_with('[') {
 803→            h.rsplit_once("]:").map(|(_, p)| p)
 804→        } else {
 805→            h.rsplit_once(':').map(|(_, p)| p)
 806→        }
 807→    }
 808→
 809→    let origin_port = get_port(origin_host);
 810→    let host_port = get_port(host);
 811→
 812→    let oh = strip_port(origin_host);
 813→    let hh = strip_port(host);
 814→
 815→    // Normalise loopback variants so 127.0.0.1 == localhost == ::1.
 816→    // Subdomains of .localhost (e.g. moltis.localhost) are also loopback per RFC 6761.
 817→    let is_loopback =
 818→        |h: &str| matches!(h, "localhost" | "127.0.0.1" | "::1") || h.ends_with(".localhost");
 819→
 820→    (oh == hh || (is_loopback(oh) && is_loopback(hh))) && origin_port == host_port
 821→}
