 941→                StatusCode::INTERNAL_SERVER_ERROR,
 942→                Json(terminal_error(
 943→                    TERMINAL_WINDOWS_LIST_FAILED,
 944→                    err.to_string(),
 945→                )),
 946→            )
 947→                .into_response(),
