 960→/// Dedicated host terminal WebSocket stream (`Settings > Terminal`).
 961→pub async fn api_terminal_ws_upgrade_handler(
 962→    ws: WebSocketUpgrade,
 963→    Query(query): Query<HostTerminalWsQuery>,
 964→    headers: axum::http::HeaderMap,
 965→    ConnectInfo(addr): ConnectInfo<SocketAddr>,
 966→    State(state): State<AppState>,
 967→) -> impl IntoResponse {
 968→    // CSWSH protection: only same-origin browser upgrades are allowed.
 969→    if let Some(origin) = headers
 970→        .get(axum::http::header::ORIGIN)
 971→        .and_then(|v| v.to_str().ok())
 972→    {
 973→        let host = headers
 974→            .get(axum::http::header::HOST)
 975→            .and_then(|v| v.to_str().ok())
 976→            .unwrap_or("");
 977→        if !is_same_origin(origin, host) {
 978→            warn!(
 979→                origin,
 980→                host,
 981→                remote = %addr,
 982→                "rejected cross-origin terminal WebSocket upgrade"
 983→            );
 984→            return (
 985→                StatusCode::FORBIDDEN,
 986→                "cross-origin WebSocket connections are not allowed",
 987→            )
 988→                .into_response();
 989→        }
 990→    }
 991→
 992→    let is_local = is_local_connection(&headers, addr, state.gateway.behind_proxy);
 993→    let header_authenticated =
 994→        websocket_header_authenticated(&headers, state.gateway.credential_store.as_ref(), is_local)
 995→            .await;
 996→    if !header_authenticated {
 997→        return (
 998→            StatusCode::UNAUTHORIZED,
 999→            Json(terminal_error(
1000→                "AUTH_NOT_AUTHENTICATED",
1001→                "not authenticated",
1002→            )),
1003→        )
1004→            .into_response();
1005→    }
1006→
1007→    let requested_window = query.window;
1008→    ws.on_upgrade(move |socket| handle_terminal_ws_connection(socket, addr, requested_window))
1009→        .into_response()
1010→}
