 82→// ── Session media ────────────────────────────────────────────────────────────
 83→
 84→/// Build a `Content-Disposition` header value for a media file.
 85→/// Uses `inline` for types browsers can render natively (PDF, text, images)
 86→/// and `attachment` for everything else so they trigger a download.
 87→/// NOTE: `text/html` is deliberately excluded — serving LLM-generated HTML
 88→/// inline on our origin would enable stored XSS.
 89→fn media_content_disposition(filename: &str, content_type: &str) -> String {
 90→    let inline = content_type.starts_with("image/")
 91→        || content_type.starts_with("audio/")
 92→        || matches!(
 93→            content_type,
 94→            "application/pdf" | "text/plain" | "text/csv" | "text/markdown"
 95→        );
 96→    let disposition = if inline {
 97→        "inline"
 98→    } else {
 99→        "attachment"
100→    };
101→    // Sanitise filename for the header (strip quotes, newlines, semicolons,
102→    // backslashes — all of which can break or inject Content-Disposition).
103→    let safe_name: String = filename
104→        .chars()
105→        .filter(|c| *c != '"' && *c != '\n' && *c != '\r' && *c != ';' && *c != '\\')
106→        .collect();
107→    format!("{disposition}; filename=\"{safe_name}\"")
108→}
