124→pub async fn api_sessions_handler(
125→    Query(query): Query<SessionListQuery>,
126→    State(state): State<AppState>,
127→) -> impl IntoResponse {
128→    match state.gateway.services.session.list().await {
129→        Ok(payload) => {
130→            if query.cursor.is_none() && query.limit.is_none() {
131→                return Json(payload).into_response();
132→            }
133→
134→            let sessions = payload
135→                .as_array()
136→                .cloned()
137→                .unwrap_or_else(Vec::<serde_json::Value>::new);
138→            let limit = clamp_session_list_limit(query.limit);
139→            let start = query
140→                .cursor
141→                .and_then(|idx| usize::try_from(idx).ok())
142→                .unwrap_or(0)
143→                .min(sessions.len());
144→            let end = start.saturating_add(limit).min(sessions.len());
145→            let page = sessions[start..end].to_vec();
146→            let next_cursor = if end < sessions.len() {
147→                u64::try_from(end).ok()
148→            } else {
149→                None
150→            };
151→
152→            Json(serde_json::json!({
153→                "sessions": page,
154→                "nextCursor": next_cursor,
155→                "hasMore": next_cursor.is_some(),
156→                "total": sessions.len(),
157→            }))
158→            .into_response()
159→        },
160→        Err(e) => api_error_response(
161→            StatusCode::INTERNAL_SERVER_ERROR,
162→            SESSION_LIST_FAILED,
163→            e.to_string(),
164→        ),
165→    }
166→}
