  1→//! API routes for configuration editing.
  2→//!
  3→//! Provides endpoints to get, validate, and save the full moltis config as TOML.
  4→//!
  5→//! SECURITY: These endpoints expose sensitive configuration including API keys.
  6→//! They are protected by auth middleware, but also have explicit checks to ensure
  7→//! they never work without authentication on non-localhost connections.
  8→
  9→use axum::{Json, extract::State, http::StatusCode, response::IntoResponse};
 10→
 11→const CONFIG_AUTH_REQUIRED: &str = "CONFIG_AUTH_REQUIRED";
 12→const CONFIG_READ_FAILED: &str = "CONFIG_READ_FAILED";
 13→const CONFIG_TOML_REQUIRED: &str = "CONFIG_TOML_REQUIRED";
 14→const CONFIG_INVALID_TOML: &str = "CONFIG_INVALID_TOML";
 15→const CONFIG_SAVE_FAILED: &str = "CONFIG_SAVE_FAILED";
 16→const CONFIG_RESTART_INVALID: &str = "CONFIG_RESTART_INVALID";
 17→const CONFIG_RESTART_READ_FAILED: &str = "CONFIG_RESTART_READ_FAILED";
 18→
 19→fn config_error(code: &str, error: impl Into<String>) -> serde_json::Value {
 20→    serde_json::json!({
 21→        "code": code,
 22→        "error": error.into(),
 23→    })
 24→}
 25→
 26→/// Check if the request should be allowed for config operations.
 27→///
 28→/// Config endpoints are ONLY allowed when:
 29→/// - Running on localhost (loopback interface only), OR
 30→/// - User is authenticated via session or API key
 31→///
 32→/// This is a defense-in-depth check on top of the auth middleware.
 33→async fn require_config_access(state: &crate::server::AppState) -> Result<(), impl IntoResponse> {
 34→    let gw = &state.gateway;
 35→
 36→    // On localhost with no password set, allow access (backward compat for initial setup)
 37→    if gw.localhost_only {
 38→        if let Some(ref cred_store) = gw.credential_store {
 39→            // If auth is explicitly disabled, allow
 40→            if cred_store.is_auth_disabled() {
 41→                return Ok(());
 42→            }
 43→            // If no password set yet, allow (initial setup)
 44→            if !cred_store.is_setup_complete() {
 45→                return Ok(());
 46→            }
 47→        } else {
 48→            // No credential store on localhost = allow
 49→            return Ok(());
 50→        }
 51→    }
 52→
 53→    // For non-localhost, we MUST have valid auth. The middleware should have
 54→    // already blocked unauthenticated requests, but if somehow we got here
 55→    // without localhost and without going through auth, block it.
 56→    if !gw.localhost_only {
 57→        if let Some(ref cred_store) = gw.credential_store {
 58→            // Auth is configured but we're not on localhost - the middleware
 59→            // should have verified auth. If auth is disabled, that's the user's
 60→            // explicit choice.
 61→            if cred_store.is_auth_disabled() {
 62→                return Ok(());
 63→            }
 64→            // Setup complete means auth is enforced - middleware handles this
 65→            if cred_store.is_setup_complete() {
 66→                // Trust that middleware verified auth
 67→                return Ok(());
 68→            }
 69→        } else {
 70→            // Non-localhost without credential store is a misconfiguration
 71→            // but we should not expose config in this case
 72→            return Err((
 73→                StatusCode::FORBIDDEN,
 74→                Json(config_error(
 75→                    CONFIG_AUTH_REQUIRED,
 76→                    "Config access requires authentication on non-localhost connections",
 77→                )),
 78→            ));
 79→        }
 80→    }
 81→
 82→    Ok(())
 83→}
