235→/// Restart the moltis process.
236→///
237→/// This re-runs the current binary with the same arguments. On Unix, it uses the exec
238→/// syscall to replace the current process. On other platforms, it spawns a new process.
239→///
240→/// Before restarting, the saved config is loaded from disk and validated. If the config
241→/// is invalid the restart is refused so the server doesn't crash on startup.
242→pub async fn restart(State(state): State<crate::server::AppState>) -> impl IntoResponse {
243→    // Extra security check for config access (restart is a privileged operation)
244→    if let Err(resp) = require_config_access(&state).await {
245→        return resp.into_response();
