269→            },
270→            Err(e) => {
271→                tracing::warn!(
272→                    path = %config_path.display(),
273→                    error = %e,
274→                    "restart refused: cannot read config file"
275→                );
276→                return (
277→                    StatusCode::INTERNAL_SERVER_ERROR,
