fn build_schema_map() -> KnownKeys {
    use KnownKeys::{Array, Leaf, Map, MapWithFields, Struct};

    let tool_policy_entry = || {
        Struct(HashMap::from([
            ("allow", Leaf),
            ("deny", Leaf),
            ("profile", Leaf),
        ]))
    };

    let provider_entry = || {
        Struct(HashMap::from([
            ("enabled", Leaf),
