    // ── Immutable (set at construction, never changes) ──────────────────────
    /// Server version string.
    pub version: String,
    /// Hostname for HelloOk.
    pub hostname: String,
    /// Loaded configuration snapshot for read-mostly request helpers.
    pub config: moltis_config::schema::MoltisConfig,
    /// Auth configuration.
