        assert_eq!(parse_git_branch("main"), None);
        assert_eq!(parse_git_branch("master"), None);
        assert_eq!(parse_git_branch(""), None);
        assert_eq!(parse_git_branch("  "), None);
        assert_eq!(
            parse_git_branch("feature/foo"),
            Some("feature/foo".to_owned())
        );
    }

