			showContent
				? html`<div class="settings-content-wrap">
					${
						mobile
							? html`<div class="settings-mobile-controls">
								<button
									class="settings-mobile-chat-btn"
									type="button"
									onClick=${() => navigate(routes.chats)}
								>
