        assert!(cfg.server.is_terminal_enabled());
    }

    #[test]
    fn terminal_enabled_parsed_from_config() {
        let cfg: MoltisConfig =
            toml::from_str("[server]\nterminal_enabled = false\n").unwrap();
        assert!(!cfg.server.terminal_enabled);
    }

    #[test]
    fn terminal_disabled_env_overrides_config() {
        let cfg: MoltisConfig = toml::from_str("").unwrap();
        assert!(cfg.server.terminal_enabled);

        // SAFETY: test runs are single-threaded for this env var; no other
        // thread reads MOLTIS_TERMINAL_DISABLED concurrently.
        unsafe {
            // env var override
            std::env::set_var("MOLTIS_TERMINAL_DISABLED", "1");
            assert!(!cfg.server.is_terminal_enabled());
            std::env::remove_var("MOLTIS_TERMINAL_DISABLED");

            // true (case-insensitive)
            std::env::set_var("MOLTIS_TERMINAL_DISABLED", "True");
            assert!(!cfg.server.is_terminal_enabled());
            std::env::remove_var("MOLTIS_TERMINAL_DISABLED");

            // non-matching value does not override
            std::env::set_var("MOLTIS_TERMINAL_DISABLED", "0");
            assert!(cfg.server.is_terminal_enabled());
            std::env::remove_var("MOLTIS_TERMINAL_DISABLED");
        }
    }
}

