        assert_eq!(config.offered, vec![
            "telegram".to_string(),
            "msteams".to_string(),
            "discord".to_string(),
            "slack".to_string(),
            "matrix".to_string(),
        ]);
    }

    #[test]
    fn channels_config_empty_toml_defaults_offered() {
        let config: ChannelsConfig = toml::from_str("").unwrap();
        assert_eq!(config.offered, vec![
            "telegram".to_string(),
            "msteams".to_string(),
            "discord".to_string(),
            "slack".to_string(),
            "matrix".to_string(),
        ]);
    }

    #[test]
    fn channels_config_explicit_offered() {
