scope = "session"
workspace_mount = "ro"
host_data_dir = "/host/moltis-data"

[wasm_tool_limits]
default_memory = 2048
default_fuel = 5000

[wasm_tool_limits.tool_overrides.calc]
fuel = 100
memory = 300
"#,
